let p = msg.payload;
if (typeof p === 'string') {
  try { p = JSON.parse(p); } catch(e) { return null; }
}

let state = null;
if (p && p.current && p.current.state) state = p.current.state;
else if (p && p.state) state = p.state;
if (!state) return null;

let reported = state.reported || {};
let desired  = state.desired  || {};

let lock = (reported.lock || desired.lock || 'chiusa').toString();
flow.set('lock', lock);

// Forza stato iniziale = chiusa (solo la PRIMA volta)
if (!flow.get('initialized')) {
  flow.set('initialized', true);
  return [ null, { lockTarget: 'chiusa', reason: 'init' } ];
}

// Detect nuova request inviata dall'ESP (reported.request)
let req = reported.request;
if (req && req.nonce) {
  if (req.nonce !== flow.get('lastReqNonce')) {
    flow.set('lastReqNonce', req.nonce);
    return [ { payload: req }, null ];
  }
}

return null;

const CODE_OK = '0000';
const chatId = Number(env.get('chatid'));

let req = msg.payload || {};
let code  = (req.code  || '').toString();
let nonce = (req.nonce || '').toString();

if (!nonce) return null;

// Se c'è già una pending request, non sovrascrivere
let pending = flow.get('pending');
if (pending && pending.nonce && Date.now() < pending.expires) {
  return [
    {
      payload: {
        chatId,
        type: 'message',
        content: 'Richiesta già in corso: premi CONFERMA entro 10 secondi.'
      }
    },
    null,
    null
  ];
}

if (code !== CODE_OK) {
  return [
    {
      payload: {
        chatId,
        type: 'message',
        content: 'Codice errato.'
      }
    },
    null,
    null
  ];
}

let lock = (flow.get('lock') || 'chiusa').toString();

// Se è CHIUSA -> serve conferma Telegram entro 10s
if (lock === 'chiusa') {
  let expires = Date.now() + 10000;
  flow.set('pending', { nonce, expires });

  // reset eventuale timer precedente
  let oldTimer = flow.get('pendingTimer');
  if (oldTimer) {
    clearTimeout(oldTimer);
    flow.set('pendingTimer', null);
  }

  // timer scadenza 10s
  let t = setTimeout(() => {
    let p = flow.get('pending');
    if (p && p.nonce === nonce && Date.now() >= p.expires) {
      flow.set('pending', null);
      flow.set('pendingTimer', null);
      node.send([
        {
          payload: {
            chatId,
            type: 'message',
            content: 'Tempo scaduto: serratura NON aperta.'
          }
        },
        null,
        null
      ]);
    }
  }, 10000);
  flow.set('pendingTimer', t);

  // Inline button con callback query (NO HTTP)
  // IMPORTANTISSIMO: reply_markup deve essere una stringa JSON
  return [
    {
      payload: {
        chatId,
        type: 'message',
        content: 'Codice corretto. Premi CONFERMA entro 10 secondi per APRIRE.',
        options: {
          reply_markup: JSON.stringify({
            inline_keyboard: [
              [ { text: 'CONFERMA', callback_data: 'CONFIRM|' + nonce } ]
            ]
          })
        }
      }
    },
    null,
    null
  ];
}

// Se è APERTA -> chiudi subito (senza Telegram)
return [
  {
    payload: {
      chatId,
      type: 'message',
      content: 'Codice corretto: chiusura automatica in corso.'
    }
  },
  { lockTarget: 'chiusa', reason: 'close' },
  null
];

let lockTarget = (msg.lockTarget || 'chiusa').toString();

msg.payload = {
  state: {
    desired: {
      welcome: 'ESIT aws-iot',
      lock: lockTarget
    },
    reported: {
      welcome: 'ESIT aws-iot',
      lock: lockTarget,

      // pulizia campi inutili (rimozione con null)
      value: null,
      pending: null,
      reqid: null,
      req_ts: null,
      op: null,
      op_ts: null,
      action: null,
      request: null
    }
  }
};

return msg;

const chatId = Number(env.get('chatid'));
let pending = flow.get('pending');

// Con telegram event (callback_query) normalmente:
// msg.payload.type = 'callback_query'
// msg.payload.content = callback_data (string)
let data = (msg.payload && msg.payload.content) ? msg.payload.content : null;

// fallback extra robusto
if (data && typeof data === 'object') {
  data = data.data || data.content || null;
}
if (!data && msg.originalMessage && msg.originalMessage.callback_query && msg.originalMessage.callback_query.data) {
  data = msg.originalMessage.callback_query.data;
}

if (!data || typeof data !== 'string') return null;
if (!data.startsWith('CONFIRM|')) return null;

let nonce = data.split('|')[1] || '';

if (!pending || !pending.nonce) {
  return [ null, { payload: { chatId, type: 'message', content: 'Nessuna richiesta in corso.' } } ];
}

if (nonce !== pending.nonce) {
  return [ null, { payload: { chatId, type: 'message', content: 'Conferma non valida (nonce mismatch).' } } ];
}

if (Date.now() > pending.expires) {
  flow.set('pending', null);
  let t = flow.get('pendingTimer');
  if (t) clearTimeout(t);
  flow.set('pendingTimer', null);

  return [ null, { payload: { chatId, type: 'message', content: 'Tempo scaduto: serratura NON aperta.' } } ];
}

// OK: apri e aggiorna shadow
flow.set('pending', null);
let t = flow.get('pendingTimer');
if (t) clearTimeout(t);
flow.set('pendingTimer', null);

return [
  { lockTarget: 'aperta', reason: 'open' },
  { payload: { chatId, type: 'message', content: 'Conferma ricevuta: serratura APERTA.' } }
];
